def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def parse_int(value: Any, default: int = 0) -> int:
    try:
        return int(float(str(value).replace(",", "").strip()))
    except Exception:
        return default


def parse_optional_float(value: Any) -> float | None:
    text = str(value or "").replace(",", "").strip()
    if not text or text.lower() in {"none", "null", "nan"}:
        return None
    try:
        return float(text)
    except Exception:
        return None


def parse_date_tag(value: str) -> str:
    text = str(value or "").strip()
    if re.fullmatch(r"\d{8}", text):
        return text
    if re.fullmatch(r"\d{4}-\d{2}-\d{2}", text):
        return text.replace("-", "")
    raise ValueError(f"无效日期: {value}")


def parse_optional_date_tag(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    return parse_date_tag(text)


def tag_to_iso(tag: str) -> str:
    return f"{tag[0:4]}-{tag[4:6]}-{tag[6:8]}"


def resolve_path(path_like: str) -> Path:
    path = Path(str(path_like))
    if path.is_absolute():
        return path
    return (PROJECT_ROOT / path).resolve()


def latest_file_in_dir(directory: Path, pattern: str) -> Path:
    files = sorted(directory.glob(pattern))
    if not files:
        raise FileNotFoundError(f"未找到文件: {directory / pattern}")
    return files[-1]


def extract_date_tag(path: Path) -> str:
    match = re.search(r"(\d{8})", path.name)
    return match.group(1) if match else datetime.now().strftime("%Y%m%d")


def resolve_merged_signals_path(date_tag: str, merged_signals_arg: str = "") -> Path:
    if merged_signals_arg:
        path = resolve_path(merged_signals_arg)
        if not path.exists():
            raise FileNotFoundError(f"未找到指定 merged_signals 文件: {path}")
        return path
    dated = MERGED_SIGNALS_DIR / f"merged_signals_{date_tag}.csv"
    if dated.exists():
        return dated
    raise FileNotFoundError(f"缺少指定日期的 merged_signals 文件: {dated}")


def sanitize_cached_market_breadth(payload: dict[str, Any], value: Any) -> float | None:
    try:
        numeric = float(value)
    except Exception:
        return None
    intraday_breadth = payload.get("intraday_breadth") or {}
    if numeric == 0.0 and isinstance(intraday_breadth, dict) and intraday_breadth.get("available") is False:
        return None
    return numeric


def load_cached_runtime_metrics(date_tag: str, config: dict[str, Any], *, profile_slug: str = "") -> dict[str, Any] | None:
    """Load cached runtime risk metrics, optionally using panel-level risk truth.

    当 profile_slug 属于三盘（aggressive/balanced/defensive）且存在对应的
    panel-level 风险真相文件时，优先读取盘级文件并应用本盘专属的
    strategy_max_drawdown_riskoff_pct 阈值，实现三盘真正的分层：
    - aggressive : 阈值 30%（全局 24.51% 不再触发该盘 halt）
    - balanced   : 阈值 22%
    - defensive  : 阈值 10%（继承原全局行为）
    """
    profile_slug = str(profile_slug or "").strip()
    use_panel_level = is_panel_level_risk_enabled(profile_slug)

    if use_panel_level:
        risk_cfg = profile_runtime_risk_config(profile_slug)
        panel_file_name = risk_cfg.get("halt_gate_source", f"runtime_risk_state_latest_{profile_slug}.json")
        runtime_state_path = REPORT_DIR / panel_file_name
    else:
        runtime_state_path = REPORT_DIR / "runtime_risk_state_latest.json"

    if not runtime_state_path.exists():
        # Fallback to global file if panel-level file does not exist yet
        fallback_path = REPORT_DIR / "runtime_risk_state_latest.json"
        if fallback_path.exists():
            runtime_state_path = fallback_path
        else:
            return None

    try:
        payload = load_json(runtime_state_path)
    except Exception:
        return None

    if str(payload.get("date_tag") or "") != str(date_tag):
        return None

    generated_at = str(payload.get("generated_at") or "").strip()
    if generated_at and str(date_tag) == datetime.now().strftime("%Y%m%d"):
        try:
            generated_dt = datetime.strptime(generated_at, "%Y-%m-%d %H:%M:%S")
            if (datetime.now() - generated_dt).total_seconds() > 15 * 60:
                return None
        except ValueError:
            return None

    runtime_metrics = payload.get("runtime_metrics") or {}
    latest_runtime = payload.get("latest_runtime") or {}
    expected_benchmark = resolve_benchmark_code(config)
    snapshot_benchmark = str(
        runtime_metrics.get("benchmark_code")
        or latest_runtime.get("benchmark_code")
        or ""
    ).strip().upper()
    if snapshot_benchmark and expected_benchmark and snapshot_benchmark != expected_benchmark:
        return None

    live_system_path = Path(
        str(
            runtime_metrics.get("live_system_path")
            or (REPORT_DIR / f"live_system_v1_{date_tag}.json")
        )
    )
    if not live_system_path.exists():
        return None
    try:
        live_payload = load_json(live_system_path)
    except Exception:
        return None

    cached_market_breadth = latest_runtime.get("market_breadth", runtime_metrics.get("market_breadth"))

    result: dict[str, Any] = {
        "market_breadth": sanitize_cached_market_breadth(payload, cached_market_breadth),
        "index_ret_pct": latest_runtime.get("index_ret_pct", runtime_metrics.get("index_ret_pct")),
        "strategy_max_dd_pct": runtime_metrics.get("strategy_max_dd_pct"),
        "strategy_sharpe": runtime_metrics.get("strategy_sharpe"),
        "benchmark_code": snapshot_benchmark or expected_benchmark,
        "live_system_path": str(live_system_path),
        "live_payload": live_payload,
        "runtime_latest": latest_runtime,
        "runtime_truth": (latest_runtime.get("runtime_truth") or {}),
        "source": f"runtime_risk_state_latest{('_' + profile_slug) if use_panel_level else ''}",
        "profile_slug": profile_slug,
        "panel_level_risk": use_panel_level,
    }

    # Apply panel-level threshold override: replace the global strategy_max_dd_pct
    # with the panel-specific risk-off threshold so that the halt gate is evaluated
    # against this panel's tolerance instead of the shared global truth.
    if use_panel_level:
        panel_risk_cfg = profile_runtime_risk_config(profile_slug)
        panel_dd_riskoff = panel_risk_cfg.get("strategy_max_drawdown_riskoff_pct")
        panel_dd_halt = panel_risk_cfg.get("strategy_max_drawdown_halt_pct")
        result["panel_strategy_max_dd_riskoff_pct"] = panel_dd_riskoff
        result["panel_strategy_max_dd_halt_pct"] = panel_dd_halt
        # Patch runtime_truth halt_new_buy logic: use panel threshold
        # 进取方案核心：优先用纸盘自己的真实回撤，没有才降级用live_system数据
        patched_truth = dict(result["runtime_truth"])
        global_dd = result["strategy_max_dd_pct"]
        paper_dd = _get_paper_real_drawdown(profile_slug)
        if paper_dd is not None:
            # 用纸盘真实回撤参与halt/riskoff评估，同时记录原始live_system值供审计
            result["_paper_real_drawdown_pct"] = paper_dd
            current_dd = paper_dd
        else:
            current_dd = global_dd
        if current_dd is not None and panel_dd_halt is not None:
            if float(current_dd) >= float(panel_dd_halt):
                patched_truth["halt_new_buy"] = True
                patched_truth["hard_stop"] = True
                patched_truth["risk_off"] = True
                patched_truth["halt_reason"] = (
                    f"panel_halt:{profile_slug}_max_drawdown_pct({current_dd:.4f}) >= {panel_dd_halt}"
                    + (f" (paper_real, live_sys={global_dd})" if paper_dd is not None else "")
                )
                patched_truth["state_reason"] = patched_truth["halt_reason"]
                patched_truth["trading_status"] = "BUY_HALT"
                patched_truth["trading_status_reason"] = patched_truth["halt_reason"]
                patched_truth["trading_status_label_cn"] = "禁止买入"
                patched_truth["buy_authorized"] = False
                patched_truth["gate_reasons"] = [
                    f"panel_halt:{profile_slug}_max_drawdown_pct({current_dd:.4f}) >= {panel_dd_halt}"
                    + (f" (paper_real)" if paper_dd is not None else "")
                ]
            elif float(current_dd) >= float(panel_dd_riskoff):
                patched_truth["halt_new_buy"] = False
                patched_truth["hard_stop"] = False
                patched_truth["risk_off"] = True
                patched_truth["halt_reason"] = (
                    f"panel_riskoff:{profile_slug}_max_drawdown_pct({current_dd:.4f}) >= {panel_dd_riskoff}"
                    + (f" (paper_real, live_sys={global_dd})" if paper_dd is not None else "")
                )
                patched_truth["state_reason"] = patched_truth["halt_reason"]
                patched_truth["trading_status"] = "RISK_OFF"
                patched_truth["trading_status_reason"] = patched_truth["halt_reason"]
                patched_truth["trading_status_label_cn"] = "降低风险"
                patched_truth["buy_authorized"] = False
                patched_truth["gate_reasons"] = [
                    f"panel_riskoff:{profile_slug}_max_drawdown_pct({current_dd:.4f}) >= {panel_dd_riskoff}"
                    + (f" (paper_real)" if paper_dd is not None else "")
                ]
            else:
                patched_truth["halt_new_buy"] = False
                patched_truth["hard_stop"] = False
                patched_truth["risk_off"] = False
                patched_truth["halt_reason"] = ""
                patched_truth["state_reason"] = "panel_normal"
                patched_truth["trading_status"] = "NORMAL"
                patched_truth["trading_status_reason"] = "panel_normal"
                patched_truth["trading_status_label_cn"] = "正常"
                patched_truth["buy_authorized"] = True
                patched_truth["gate_reasons"] = []
        result["runtime_truth"] = patched_truth

    return result


def _get_paper_real_drawdown(profile_slug: str) -> float | None:
    """Get paper account's real max_drawdown_pct from its latest trading metrics.
    Returns None if no metrics file exists yet (legacy paper accounts).
    进取方案核心：用纸盘自己的真实数据，而非live_system回测数据。
    """
    files = sorted((REPORT_DIR).glob(f"paper_{profile_slug}_trading_metrics_*.json"))
    if not files:
        return None
    try:
        d = load_json(files[-1])
        dd = d.get("metrics", {}).get("max_drawdown_pct")
        if dd is not None:
            return float(dd)
    except Exception:
        pass
    return None


def resolve_runtime_metrics(date_tag: str, config: dict[str, Any], *, profile_slug: str = "") -> dict[str, Any]:
    cached = load_cached_runtime_metrics(date_tag, config, profile_slug=profile_slug)
    if cached is not None:
        return cached
    return load_runtime_metrics_for_date(date_tag, config, report_dir=REPORT_DIR)


def apply_cached_runtime_truth(runtime: Any, runtime_metrics: dict[str, Any], *, date_tag: str) -> Any:
    if str(getattr(runtime, "date_tag", "") or "") != str(date_tag):
        return runtime

    runtime_truth = runtime_metrics.get("runtime_truth") or {}
    runtime_latest = runtime_metrics.get("runtime_latest") or {}
    source = runtime_metrics.get("source", "")
    # Accept both the global source and panel-level sources (runtime_risk_state_latest_aggressive, etc.)
    is_cached = source == "runtime_risk_state_latest" or source.startswith("runtime_risk_state_latest_")
    if not is_cached:
        return runtime

    authoritative = runtime_truth if isinstance(runtime_truth, dict) and runtime_truth else runtime_latest
    if not isinstance(authoritative, dict) or not authoritative:
        return runtime

    runtime.mode = str(authoritative.get("mode") or getattr(runtime, "mode", "") or "")
    runtime.risk_off = bool(authoritative.get("risk_off", getattr(runtime, "risk_off", False)))
    runtime.hard_stop = bool(authoritative.get("hard_stop", getattr(runtime, "hard_stop", False)))
    runtime.halt_new_buy = bool(authoritative.get("halt_new_buy", getattr(runtime, "halt_new_buy", False)))
    runtime.halt_reason = str(
        authoritative.get("trading_status_reason")
        or authoritative.get("state_reason")
        or authoritative.get("halt_reason")
        or getattr(runtime, "halt_reason", "")
        or ""
    )
    gate_reasons = authoritative.get("gate_reasons")
    if isinstance(gate_reasons, list):
        runtime.gate_reasons = [str(item).strip() for item in gate_reasons if str(item).strip()]
    market_breadth = authoritative.get("market_breadth", runtime_metrics.get("market_breadth"))
    if market_breadth is not None:
        try:
            runtime.market_breadth = float(market_breadth)
        except Exception:
            pass
    return runtime


